import Konva from 'konva'
import { type RefObject, useCallback, useRef } from 'react'

// CRITICAL: Enable hit detection during drag — without this, the second touch
// is swallowed during a pan gesture and pinch-zoom fails on mobile.
Konva.hitOnDragEnabled = true

/* ──────────────── Constants ──────────────── */

const MIN_SCALE = 0.3
const MAX_SCALE = 4
/** 10% per scroll tick — smooth incremental zoom */
const SCROLL_SCALE_BY = 1.1
/** 30% per button click — larger step for discoverability */
const BUTTON_SCALE_BY = 1.3

/* ──────────────── Helpers ──────────────── */

function clamp(val: number, min: number, max: number): number {
  return Math.min(Math.max(val, min), max)
}

function getDistance(p1: { x: number; y: number }, p2: { x: number; y: number }): number {
  return Math.sqrt((p2.x - p1.x) ** 2 + (p2.y - p1.y) ** 2)
}

function getCenter(
  p1: { x: number; y: number },
  p2: { x: number; y: number },
): { x: number; y: number } {
  return { x: (p1.x + p2.x) / 2, y: (p1.y + p2.y) / 2 }
}

function getAngle(p1: { x: number; y: number }, p2: { x: number; y: number }): number {
  return Math.atan2(p2.y - p1.y, p2.x - p1.x)
}

/* ──────────────── Exported gesture math helpers ──────────────── */

/**
 * Convert a container-relative screen point to stage-local coordinates using
 * Konva's absolute inverse transform. Correct at any rotation angle — unlike
 * the naive `(screenX - stage.x()) / stage.scaleX()` formula which fails when
 * the stage is rotated.
 */
export type StageForGesture = {
  getAbsoluteTransform: () => {
    copy: () => { invert: () => { point: (p: { x: number; y: number }) => { x: number; y: number } } }
  }
  container: () => { getBoundingClientRect: () => { left: number; top: number } }
}

export function toStageLocalFromScreen(
  stage: StageForGesture,
  screenPoint: { x: number; y: number },
): { x: number; y: number } {
  const rect = stage.container().getBoundingClientRect()
  const containerRelative = { x: screenPoint.x - rect.left, y: screenPoint.y - rect.top }
  return stage.getAbsoluteTransform().copy().invert().point(containerRelative)
}

/**
 * Compute the stage position that keeps a given stage-local anchor point fixed
 * under a given screen position after applying newScale and newRotationDeg.
 *
 * Uses a Konva.Transform forward projection: rotate → scale → subtract from
 * screenCenter to find the required stage translation.
 */
export function computePivotPosition(
  stageLocal: { x: number; y: number },
  screenCenter: { x: number; y: number },
  newScale: number,
  newRotationDeg: number,
): { x: number; y: number } {
  const t = new Konva.Transform()
  t.rotate((newRotationDeg * Math.PI) / 180)
  t.scale(newScale, newScale)
  const projected = t.point(stageLocal)
  return {
    x: screenCenter.x - projected.x,
    y: screenCenter.y - projected.y,
  }
}

/**
 * Returns true if the per-frame angular delta (in degrees) exceeds the 2-degree
 * jitter threshold, meaning the rotation should be applied. Strict greater-than:
 * exactly 2° returns false.
 */
export function applyRotationThreshold(angleDiffDeg: number): boolean {
  return Math.abs(angleDiffDeg) > 2
}

/* ──────────────── Hook ──────────────── */

interface UseMapViewportOptions {
  stageRef: RefObject<Konva.Stage | null>
  imageRect: { x: number; y: number; width: number; height: number } | null
  onScaleChange?: (scale: number) => void
}

export function useMapViewport({ stageRef, imageRect, onScaleChange }: UseMapViewportOptions): {
  handleWheel: (e: Konva.KonvaEventObject<WheelEvent>) => void
  handleTouchMove: (e: Konva.KonvaEventObject<TouchEvent>) => void
  handleTouchEnd: () => void
  handleDragEnd: () => void
  zoomByButton: (direction: 1 | -1) => void
  fitToScreen: (viewportWidth: number, viewportHeight: number, animate?: boolean) => void
} {
  const lastDist = useRef<number>(0)
  const lastCenter = useRef<{ x: number; y: number } | null>(null)
  const lastAngle = useRef<number | null>(null)
  const activeTween = useRef<Konva.Tween | null>(null)

  /**
   * Pointer-centric zoom (INSTANT — no Tween).
   * Zooms toward cursor position like Google Maps.
   * Rapid scroll events must NOT create stacked animations.
   */
  const handleWheel = useCallback(
    (e: Konva.KonvaEventObject<WheelEvent>) => {
      const stage = stageRef.current
      if (!stage) return

      e.evt.preventDefault()

      const pointer = stage.getPointerPosition()
      if (!pointer) return

      const oldScale = stage.scaleX()

      // The point in stage-local coordinates under the cursor
      const mousePointTo = {
        x: (pointer.x - stage.x()) / oldScale,
        y: (pointer.y - stage.y()) / oldScale,
      }

      // Determine direction: deltaY > 0 = scroll down = zoom out
      // ctrlKey is set for trackpad pinch gestures → invert
      let direction = e.evt.deltaY > 0 ? -1 : 1
      if (e.evt.ctrlKey) direction = -direction

      const newScale = clamp(
        direction > 0 ? oldScale * SCROLL_SCALE_BY : oldScale / SCROLL_SCALE_BY,
        MIN_SCALE,
        MAX_SCALE,
      )

      // Apply DIRECTLY to stage node — no React setState, no Tween
      stage.scale({ x: newScale, y: newScale })
      stage.position({
        x: pointer.x - mousePointTo.x * newScale,
        y: pointer.y - mousePointTo.y * newScale,
      })
      onScaleChange?.(newScale)
    },
    [stageRef, onScaleChange],
  )

  /**
   * Multi-touch pinch-zoom + rotation.
   * Single finger = pan (handled by Stage draggable).
   * Two fingers = pinch-zoom + optional rotation.
   */
  const handleTouchMove = useCallback(
    (e: Konva.KonvaEventObject<TouchEvent>) => {
      const stage = stageRef.current
      if (!stage) return

      const touches = e.evt.touches
      // Only prevent default for multi-touch (pinch/rotate) — single-finger
      // drag must reach Konva's draggable handler via native touch events
      if (touches.length >= 2) {
        e.evt.preventDefault()
      }
      if (touches.length < 2) return

      // Hand off from single-finger drag to two-finger pinch
      if (stage.isDragging()) {
        stage.stopDrag()
      }

      const t0 = touches[0]
      const t1 = touches[1]
      if (!t0 || !t1) return

      const p1 = { x: t0.clientX, y: t0.clientY }
      const p2 = { x: t1.clientX, y: t1.clientY }

      const dist = getDistance(p1, p2)
      const center = getCenter(p1, p2)
      const angle = getAngle(p1, p2)

      // First frame of gesture — store initial values
      if (lastDist.current === 0) {
        lastDist.current = dist
        lastCenter.current = center
        lastAngle.current = angle
        return
      }

      // Step 1: Get container-relative screen center
      const rect = stage.container().getBoundingClientRect()
      const screenCenter = { x: center.x - rect.left, y: center.y - rect.top }

      // Step 2: Read stage-local point under finger BEFORE any mutation
      // (getAbsoluteTransform is live — must capture before scale/rotation changes)
      const stageLocal = stage.getAbsoluteTransform().copy().invert().point(screenCenter)

      // Step 3: Compute and apply scale mutation, then notify callback
      const newScale = clamp(stage.scaleX() * (dist / lastDist.current), MIN_SCALE, MAX_SCALE)
      stage.scaleX(newScale)
      stage.scaleY(newScale)
      onScaleChange?.(newScale)

      // Step 4: Apply rotation only if per-frame delta exceeds 2-degree threshold
      const angleDiffDeg = (angle - (lastAngle.current ?? angle)) * (180 / Math.PI)
      if (applyRotationThreshold(angleDiffDeg)) {
        stage.rotation(stage.rotation() + angleDiffDeg)
      }

      // Step 5: Recalculate position — keep stageLocal under screenCenter
      // Forward-projects stageLocal through current (post-mutation) rotation + scale
      const newPos = computePivotPosition(stageLocal, screenCenter, newScale, stage.rotation())
      stage.position(newPos)

      // Update refs for next frame
      lastDist.current = dist
      lastCenter.current = center
      lastAngle.current = angle
    },
    [stageRef, onScaleChange],
  )

  /**
   * Reset touch tracking refs when gesture ends.
   */
  const handleTouchEnd = useCallback(() => {
    lastDist.current = 0
    lastCenter.current = null
    lastAngle.current = null
  }, [])

  /**
   * Elastic snap-back: soft bounds that pull the floor plan back
   * when dragged too far off-screen.
   */
  const handleDragEnd = useCallback(() => {
    const stage = stageRef.current
    if (!stage || !imageRect) return

    const scale = stage.scaleX()
    const stagePos = stage.position()

    // Floor plan edges in viewport (screen) coordinates
    const left = imageRect.x * scale + stagePos.x
    const right = (imageRect.x + imageRect.width) * scale + stagePos.x
    const top = imageRect.y * scale + stagePos.y
    const bottom = (imageRect.y + imageRect.height) * scale + stagePos.y

    const margin = 100 // pixels of allowed overscroll
    let newX = stagePos.x
    let newY = stagePos.y
    let needsSnap = false

    // Horizontal bounds
    if (right < margin) {
      newX = margin - (imageRect.x + imageRect.width) * scale
      needsSnap = true
    } else if (left > stage.width() - margin) {
      newX = stage.width() - margin - imageRect.x * scale
      needsSnap = true
    }

    // Vertical bounds
    if (bottom < margin) {
      newY = margin - (imageRect.y + imageRect.height) * scale
      needsSnap = true
    } else if (top > stage.height() - margin) {
      newY = stage.height() - margin - imageRect.y * scale
      needsSnap = true
    }

    if (needsSnap) {
      if (activeTween.current) {
        activeTween.current.destroy()
        activeTween.current = null
      }
      const tween = new Konva.Tween({
        node: stage,
        duration: 0.3,
        x: newX,
        y: newY,
        easing: Konva.Easings.EaseInOut,
      })
      tween.play()
      activeTween.current = tween
    }
  }, [stageRef, imageRect])

  /**
   * Animated zoom toward viewport center (for +/- buttons).
   * Uses Konva.Tween for smooth eased transition.
   */
  const zoomByButton = useCallback(
    (direction: 1 | -1) => {
      const stage = stageRef.current
      if (!stage) return

      const oldScale = stage.scaleX()
      const newScale = clamp(
        direction > 0 ? oldScale * BUTTON_SCALE_BY : oldScale / BUTTON_SCALE_BY,
        MIN_SCALE,
        MAX_SCALE,
      )

      const center = { x: stage.width() / 2, y: stage.height() / 2 }
      const mousePointTo = {
        x: (center.x - stage.x()) / oldScale,
        y: (center.y - stage.y()) / oldScale,
      }
      const newPos = {
        x: center.x - mousePointTo.x * newScale,
        y: center.y - mousePointTo.y * newScale,
      }

      if (activeTween.current) {
        activeTween.current.destroy()
        activeTween.current = null
      }

      const tween = new Konva.Tween({
        node: stage,
        duration: 0.25,
        scaleX: newScale,
        scaleY: newScale,
        x: newPos.x,
        y: newPos.y,
        easing: Konva.Easings.EaseInOut,
        onFinish: () => onScaleChange?.(newScale),
      })
      tween.play()
      activeTween.current = tween
    },
    [stageRef, onScaleChange],
  )

  /**
   * Reset stage transform to identity (scale=1, pos=0, rotation=0).
   * FloorPlanImage handles the actual fit-to-screen calculation internally.
   */
  const fitToScreen = useCallback(
    (_viewportWidth: number, _viewportHeight: number, animate = false) => {
      const stage = stageRef.current
      if (!stage || !imageRect) return

      if (animate) {
        if (activeTween.current) {
          activeTween.current.destroy()
          activeTween.current = null
        }
        const tween = new Konva.Tween({
          node: stage,
          duration: 0.3,
          scaleX: 1,
          scaleY: 1,
          x: 0,
          y: 0,
          rotation: 0,
          easing: Konva.Easings.EaseInOut,
          onFinish: () => onScaleChange?.(1),
        })
        tween.play()
        activeTween.current = tween
      } else {
        stage.scale({ x: 1, y: 1 })
        stage.position({ x: 0, y: 0 })
        stage.rotation(0)
        onScaleChange?.(1)
      }
    },
    [stageRef, imageRect, onScaleChange],
  )

  return {
    handleWheel,
    handleTouchMove,
    handleTouchEnd,
    handleDragEnd,
    zoomByButton,
    fitToScreen,
  }
}

import { PathfindingEngine } from '@shared/pathfinding/engine'
import type { PathResult } from '@shared/pathfinding/types'
import type { NavBuilding, NavFloor, NavNode } from '@shared/types'
import type Konva from 'konva'
import KonvaModule from 'konva'
import { useCallback, useEffect, useMemo, useRef, useState } from 'react'
import { Layer, Stage, Text } from 'react-konva'
import { filterNodesByActiveFloor, filterRouteSegmentByFloor, totalFloorCount } from '../hooks/useFloorFiltering'
import { useFloorPlanImage } from '../hooks/useFloorPlanImage'
import { useGraphData } from '../hooks/useGraphData'
import { useMapViewport } from '../hooks/useMapViewport'
import { routesAreIdentical, useRouteDirections } from '../hooks/useRouteDirections'
import { useRouteSelection } from '../hooks/useRouteSelection'
import { useViewportSize } from '../hooks/useViewportSize'
import { DirectionsSheet } from './DirectionsSheet'
import FloorPlanImage from './FloorPlanImage'
import { FloorTabStrip } from './FloorTabStrip'
import GridBackground from './GridBackground'
import { LandmarkLayer } from './LandmarkLayer'
import { LocationDetailSheet } from './LocationDetailSheet'
import { RouteLayer } from './RouteLayer'
import { SearchOverlay } from './SearchOverlay'
import { SelectionMarkerLayer } from './SelectionMarkerLayer'
import ZoomControls from './ZoomControls'

/* ──────────────── Types ──────────────── */

interface RouteResult {
  standard: PathResult
  accessible: PathResult
}

/* ──────────────── Component ──────────────── */

/**
 * Main floor plan canvas container.
 *
 * Full-viewport layout — the entire viewport is the map (no header).
 * Renders: SearchOverlay → grid background → floor plan image → landmarks → pins → loading/error.
 * Interactive: pan (drag), zoom (scroll/buttons), pinch-zoom, rotation (mobile).
 */
export default function FloorPlanCanvas() {
  const { width, height } = useViewportSize()

  // ── Active floor/building state ──
  const [activeBuildingId, setActiveBuildingId] = useState<number | 'campus' | null>(null)
  const [activeFloorId, setActiveFloorId] = useState<number | null>(null)

  const stageRef = useRef<Konva.Stage>(null)
  const [imageRect, setImageRect] = useState<{
    x: number
    y: number
    width: number
    height: number
  } | null>(null)
  const [stageScale, setStageScale] = useState<number>(1)
  const [activeMode, setActiveMode] = useState<'standard' | 'accessible'>('standard')
  const [sheetOpen, setSheetOpen] = useState<boolean>(false)
  // routeVisible tracks whether the route line should be drawn — decoupled from sheetOpen
  // so the line stays visible after pressing Back (sheet closes but route remains)
  const [routeVisible, setRouteVisible] = useState<boolean>(false)
  // detailNode — tracks which landmark is being viewed in the detail sheet
  const [detailNode, setDetailNode] = useState<NavNode | null>(null)

  const routeSelection = useRouteSelection()
  const graphState = useGraphData()

  // Route computation result — fully consumed by RouteLayer and DirectionsSheet
  const [routeResult, setRouteResult] = useState<RouteResult | null>(null)

  // Toast state
  const [toast, setToast] = useState<{ message: string; isError: boolean } | null>(null)
  const toastTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null)

  // ── All buildings from the graph ──
  const allBuildings = useMemo<NavBuilding[]>(() => {
    if (graphState.status !== 'loaded') return []
    return graphState.data.buildings
  }, [graphState])

  // Non-campus buildings for the building selector
  const nonCampusBuildings = useMemo(
    () => allBuildings.filter(b => b.name !== 'Campus'),
    [allBuildings],
  )

  // Campus building (may be undefined — only present if admin uploaded campus map)
  const campusBuilding = useMemo(
    () => allBuildings.find(b => b.name === 'Campus'),
    [allBuildings],
  )

  // The active NavBuilding object
  const activeBuilding = useMemo(() => {
    if (activeBuildingId === 'campus') return campusBuilding
    if (activeBuildingId === null) return undefined
    return allBuildings.find(b => b.id === activeBuildingId)
  }, [activeBuildingId, allBuildings, campusBuilding])

  // Sorted floors for the active building (for floor tab buttons)
  const sortedActiveFloors = useMemo(
    () => (activeBuilding?.floors ?? []).slice().sort((a, b) => a.floorNumber - b.floorNumber),
    [activeBuilding],
  )

  // The currently active NavFloor object
  const activeFloor = useMemo(
    () => sortedActiveFloors.find(f => f.id === activeFloorId) ?? null,
    [sortedActiveFloors, activeFloorId],
  )

  // Floor count across all buildings — used to show/hide the tab strip
  const floorCount = useMemo(() => totalFloorCount(allBuildings), [allBuildings])

  // Compute target for useFloorPlanImage — must be stable (not constructed inline) to avoid hook dependency issues
  const floorImageTarget = useMemo<{ buildingId: number; floorNumber: number } | 'campus' | undefined>(() => {
    if (activeBuildingId === 'campus') return 'campus'
    if (!activeBuilding || !activeFloor) return undefined
    return { buildingId: activeBuilding.id, floorNumber: activeFloor.floorNumber }
  }, [activeBuildingId, activeBuilding, activeFloor])

  const { image, isLoading, isFailed, isFullLoaded } = useFloorPlanImage(floorImageTarget)

  // Get nodes array when graph is loaded — flatten from buildings → floors → nodes
  const nodes = useMemo(() => {
    if (graphState.status !== 'loaded') return []
    return graphState.data.buildings.flatMap((b) => b.floors.flatMap((f) => f.nodes))
  }, [graphState])

  // Node map for direction step lookup
  const nodeMap = useMemo<Map<string, NavNode>>(() => {
    return new Map(nodes.map((n) => [n.id, n]))
  }, [nodes])

  // Floor map for floor-change direction step lookup (floor number by floor ID)
  const floorMap = useMemo<Map<number, NavFloor>>(() => {
    if (graphState.status !== 'loaded') return new Map()
    return new Map(
      graphState.data.buildings.flatMap((b) => b.floors).map((f) => [f.id, f]),
    )
  }, [graphState])

  // Show tab strip: only when > 1 total floor AND DirectionsSheet is closed
  const showTabStrip = graphState.status === 'loaded' && floorCount > 1 && !sheetOpen

  // Filtered nodes for LandmarkLayer — active floor + dimmed adjacent elevator connectors
  const { nodes: filteredNodes, dimmedNodeIds } = useMemo(() => {
    if (!activeFloor) return { nodes: [] as NavNode[], dimmedNodeIds: new Set<string>() }
    return filterNodesByActiveFloor(nodes, activeFloor.id)
  }, [nodes, activeFloor])

  // Compute turn-by-turn directions for each mode
  const standardDirections = useRouteDirections(routeResult?.standard ?? null, nodeMap, 'standard', floorMap)
  const accessibleDirections = useRouteDirections(
    routeResult?.accessible ?? null,
    nodeMap,
    'accessible',
    floorMap,
  )
  const routesIdentical = routeResult
    ? routesAreIdentical(routeResult.standard, routeResult.accessible)
    : false

  // Memoize PathfindingEngine from loaded NavGraph
  const engine = useMemo(() => {
    if (graphState.status === 'loaded') return new PathfindingEngine(graphState.data)
    return null
  }, [graphState])

  // Node IDs to hide from LandmarkLayer (replaced by A/B pins)
  const hiddenNodeIds = useMemo(() => {
    const ids: string[] = []
    if (routeSelection.start) ids.push(routeSelection.start.id)
    if (routeSelection.destination) ids.push(routeSelection.destination.id)
    return ids
  }, [routeSelection.start, routeSelection.destination])

  const { handleWheel, handleTouchMove, handleTouchEnd, handleDragEnd, zoomByButton, fitToScreen } =
    useMapViewport({ stageRef, imageRect, onScaleChange: setStageScale })

  // Re-fit floor plan when viewport size changes (e.g. orientation change)
  // biome-ignore lint/correctness/useExhaustiveDependencies: intentional — re-fit on viewport resize only when image is loaded
  useEffect(() => {
    if (image && imageRect) {
      fitToScreen(width, height, true)
    }
  }, [width, height])

  // Default initialization — on first graph load, set active floor to Floor 1 of first non-campus building
  // biome-ignore lint/correctness/useExhaustiveDependencies: initialize once on first load
  useEffect(() => {
    if (graphState.status !== 'loaded') return
    if (activeFloorId !== null) return // already initialized
    const firstBuilding = graphState.data.buildings.find(b => b.name !== 'Campus')
    if (!firstBuilding) return
    const floor1 = firstBuilding.floors
      .slice()
      .sort((a, b) => a.floorNumber - b.floorNumber)[0]
    if (floor1) {
      setActiveBuildingId(firstBuilding.id)
      setActiveFloorId(floor1.id)
    }
  }, [graphState.status])

  /** Show a toast notification that auto-dismisses after 3 seconds */
  const showToast = useCallback((message: string, isError = false) => {
    if (toastTimerRef.current) clearTimeout(toastTimerRef.current)
    setToast({ message, isError })
    toastTimerRef.current = setTimeout(() => setToast(null), 3000)
  }, [])

  /**
   * Animate the stage to frame both nodeA and nodeB with ~15% padding.
   * Converts normalized coords to pixel coords using imageRect, computes
   * required scale and position, and applies via Konva.Tween.
   */
  const fitToBounds = useCallback(
    (nodeA: { x: number; y: number }, nodeB: { x: number; y: number }) => {
      const stage = stageRef.current
      if (!stage || !imageRect) return

      // Convert normalized coords to pixel coords
      const ax = imageRect.x + nodeA.x * imageRect.width
      const ay = imageRect.y + nodeA.y * imageRect.height
      const bx = imageRect.x + nodeB.x * imageRect.width
      const by = imageRect.y + nodeB.y * imageRect.height

      // Bounding box of both points
      const minX = Math.min(ax, bx)
      const maxX = Math.max(ax, bx)
      const minY = Math.min(ay, by)
      const maxY = Math.max(ay, by)
      const boundsW = maxX - minX
      const boundsH = maxY - minY

      // Add 15% padding on all sides (30% total per axis)
      const padding = 0.15
      const paddedW = boundsW * (1 + 2 * padding) || width * 0.5
      const paddedH = boundsH * (1 + 2 * padding) || height * 0.5

      // Scale to fit padded bounds in viewport
      const scaleX = width / paddedW
      const scaleY = height / paddedH
      const newScale = Math.min(scaleX, scaleY, 4) // cap at MAX_SCALE

      // Center of the bounding box
      const centerX = (minX + maxX) / 2
      const centerY = (minY + maxY) / 2

      // Stage position to center the bounding box in viewport
      const newX = width / 2 - centerX * newScale
      const newY = height / 2 - centerY * newScale

      const tween = new KonvaModule.Tween({
        node: stage,
        duration: 0.4,
        scaleX: newScale,
        scaleY: newScale,
        x: newX,
        y: newY,
        easing: KonvaModule.Easings.EaseInOut,
        onFinish: () => setStageScale(newScale),
      })
      tween.play()
    },
    [imageRect, width, height],
  )

  /** Switch to a new floor — updates state and re-fits the canvas */
  const handleFloorSwitch = useCallback(
    (floor: NavFloor) => {
      const building = allBuildings.find(b => b.floors.some(f => f.id === floor.id))
      if (building) setActiveBuildingId(building.id)
      setActiveFloorId(floor.id)
      fitToScreen(width, height, true)
    },
    [allBuildings, width, height, fitToScreen],
  )

  /** Switch to a different building — defaults to Floor 1 (or campus floor) */
  const handleBuildingSwitch = useCallback(
    (id: number | 'campus') => {
      setActiveBuildingId(id)
      if (id === 'campus') {
        // Campus has exactly one map — no floor tabs. Set activeFloorId to campus floor id.
        const campusBld = allBuildings.find(b => b.name === 'Campus')
        const campusFloor = campusBld?.floors[0]
        if (campusFloor) setActiveFloorId(campusFloor.id)
      } else {
        // Switch to floor 1 (lowest floorNumber) of the newly selected building
        const bld = allBuildings.find(b => b.id === id)
        const firstFloor = bld?.floors.slice().sort((a, b) => a.floorNumber - b.floorNumber)[0]
        if (firstFloor) setActiveFloorId(firstFloor.id)
        fitToScreen(width, height, true)
      }
    },
    [allBuildings, width, height, fitToScreen],
  )

  /** Compute route and trigger auto-pan when both start and destination are set */
  const handleRouteTrigger = useCallback(() => {
    if (!routeSelection.start || !routeSelection.destination || !engine) return

    // Auto-pan to show both pins
    fitToBounds(routeSelection.start, routeSelection.destination)

    // Compute routes
    const standard = engine.findRoute(
      routeSelection.start.id,
      routeSelection.destination.id,
      'standard',
    )
    const accessible = engine.findRoute(
      routeSelection.start.id,
      routeSelection.destination.id,
      'accessible',
    )
    setRouteResult({ standard, accessible })

    if (standard.found || accessible.found) {
      setSheetOpen(true)
      setRouteVisible(true)
      setActiveMode('standard')
      showToast('Route calculated')

      // Auto-switch to start node's floor so student sees where journey begins
      if (routeSelection.start) {
        const startFloor = floorMap.get(routeSelection.start.floorId)
        if (startFloor) handleFloorSwitch(startFloor)
      }
    } else {
      showToast('No route found', true)
    }
  }, [routeSelection.start, routeSelection.destination, engine, fitToBounds, showToast, floorMap, handleFloorSwitch])

  // Clear route result and close sheet when selections change (start or dest cleared)
  useEffect(() => {
    if (!routeSelection.start || !routeSelection.destination) {
      setRouteResult(null)
      setSheetOpen(false)
      setRouteVisible(false)
    }
  }, [routeSelection.start, routeSelection.destination])

  // Close detail sheet when both endpoints are set and route is triggered
  useEffect(() => {
    if (routeSelection.start !== null && routeSelection.destination !== null) {
      setDetailNode(null)
    }
  }, [routeSelection.start, routeSelection.destination])

  /** Back arrow in directions sheet — close sheet only, keep route line visible */
  const handleSheetBack = useCallback(() => {
    setSheetOpen(false)
  }, [])

  /** Combined landmark tap handler: show detail sheet AND feed route selection.
   *  Also auto-switches floor when tapping a dimmed elevator connector. */
  const handleLandmarkTap = useCallback(
    (node: NavNode) => {
      // Auto-switch floor when tapping a node on a different floor (e.g. dimmed elevator connector)
      if (activeFloor && node.floorId !== activeFloor.id) {
        const targetFloor = floorMap.get(node.floorId)
        if (targetFloor) {
          handleFloorSwitch(targetFloor)
          return // Don't open detail sheet on auto-switch tap
        }
      }
      setDetailNode(node)
      routeSelection.setFromTap(node)
    },
    [routeSelection, activeFloor, floorMap, handleFloorSwitch],
  )

  /** Convert node IDs to flat pixel coordinate array for RouteLayer */
  const buildRoutePoints = useCallback(
    (nodeIds: string[]): number[] => {
      if (!imageRect) return []
      const pts: number[] = []
      for (const id of nodeIds) {
        const n = nodeMap.get(id)
        if (!n) continue
        pts.push(imageRect.x + n.x * imageRect.width, imageRect.y + n.y * imageRect.height)
      }
      return pts
    },
    [imageRect, nodeMap],
  )

  // Active route points — filtered to the currently active floor only
  const activeRoutePoints = useMemo(() => {
    if (!routeResult || !activeFloor) return []
    const result = activeMode === 'standard' ? routeResult.standard : routeResult.accessible
    if (!result.found) return []
    const floorNodeIds = filterRouteSegmentByFloor(result.nodeIds, nodeMap, activeFloor.id)
    return buildRoutePoints(floorNodeIds)
  }, [routeResult, activeMode, activeFloor, nodeMap, buildRoutePoints])

  const activeRouteColor = activeMode === 'standard' ? '#3b82f6' : '#22c55e'

  const interactionDisabled = isLoading || isFailed

  return (
    <div className="relative w-full h-full">
      {/* Search overlay — HTML sibling above Stage in DOM */}
      <SearchOverlay
        selection={routeSelection}
        nodes={nodes}
        onRouteTrigger={handleRouteTrigger}
        sheetOpen={sheetOpen}
        hasRoute={routeResult !== null}
        onOpenSheet={() => setSheetOpen(true)}
      />

      {/* Graph data loading overlay — shows while useGraphData fetches from server */}
      {graphState.status === 'loading' && (
        <div className="absolute inset-0 flex items-center justify-center z-10 pointer-events-none">
          <div className="flex flex-col items-center gap-3 bg-white/80 backdrop-blur-sm rounded-xl px-6 py-4 shadow">
            <div className="w-8 h-8 border-4 border-blue-500 border-t-transparent rounded-full animate-spin" />
            <span className="text-sm text-slate-600 font-medium">Loading map data…</span>
          </div>
        </div>
      )}

      {/* Graph data error overlay — shows after all retries exhausted */}
      {graphState.status === 'error' && (
        <div className="absolute inset-0 flex items-center justify-center z-10 pointer-events-none">
          <div className="flex flex-col items-center gap-2 bg-white/90 backdrop-blur-sm rounded-xl px-6 py-4 shadow border border-red-200">
            <span className="text-red-500 font-semibold text-sm">Failed to load map data</span>
            <span className="text-slate-500 text-xs">Please refresh the page to try again</span>
          </div>
        </div>
      )}

      <Stage
        ref={stageRef}
        width={width}
        height={height}
        draggable={!interactionDisabled}
        onWheel={handleWheel}
        onTouchMove={handleTouchMove}
        onTouchEnd={handleTouchEnd}
        onDragEnd={handleDragEnd}
      >
        {/* Grid — static background, not transformed */}
        <Layer>
          <GridBackground width={width} height={height} />
        </Layer>

        {/* Content — floor plan image */}
        <Layer>
          {!isLoading && !isFailed && image && (
            <FloorPlanImage
              image={image}
              isFullLoaded={isFullLoaded}
              viewportWidth={width}
              viewportHeight={height}
              onImageRectChange={setImageRect}
            />
          )}
        </Layer>

        {/* Route path — animated dashed line for active route */}
        <RouteLayer
          points={activeRoutePoints}
          color={activeRouteColor}
          visible={routeVisible && activeRoutePoints.length >= 4}
        />

        {/* Landmarks — markers above floor plan image, filtered to active floor */}
        <LandmarkLayer
          nodes={filteredNodes}
          imageRect={imageRect}
          stageScale={stageScale}
          selectedNodeId={null}
          onSelectNode={handleLandmarkTap}
          hiddenNodeIds={hiddenNodeIds}
          dimmedNodeIds={dimmedNodeIds}
        />

        {/* Selection pins — A/B labeled markers above landmarks */}
        <SelectionMarkerLayer
          start={routeSelection.start}
          destination={routeSelection.destination}
          imageRect={imageRect}
          stageScale={stageScale}
          onClearStart={routeSelection.clearStart}
          onClearDestination={routeSelection.clearDestination}
        />

        {/* UI overlay — loading/error states */}
        <Layer>
          {isLoading && (
            <Text
              x={width / 2 - 100}
              y={height / 2 - 10}
              width={200}
              align="center"
              text="Loading floor plan..."
              fontSize={18}
              fill="#64748b"
            />
          )}
          {isFailed && (
            <Text
              x={width / 2 - 130}
              y={height / 2 - 10}
              width={260}
              align="center"
              text="Failed to load floor plan"
              fontSize={18}
              fill="#ef4444"
            />
          )}
        </Layer>
      </Stage>

      <ZoomControls
        onZoomIn={() => zoomByButton(1)}
        onZoomOut={() => zoomByButton(-1)}
        disabled={interactionDisabled}
      />

      <LocationDetailSheet node={detailNode} onClose={() => setDetailNode(null)} />

      <DirectionsSheet
        open={sheetOpen}
        standard={routeResult?.standard ?? null}
        accessible={routeResult?.accessible ?? null}
        standardDirections={standardDirections}
        accessibleDirections={accessibleDirections}
        routesIdentical={routesIdentical}
        activeMode={activeMode}
        onTabChange={setActiveMode}
        onBack={handleSheetBack}
        startNode={routeSelection.start}
        destNode={routeSelection.destination}
      />

      {/* Canvas legend — color key for route lines, floats above sheet when open */}
      {routeVisible &&
        routeResult &&
        (routeResult.standard.found || routeResult.accessible.found) && (
          <div
            className="absolute left-3 z-20 bg-white/90 backdrop-blur-sm rounded-lg shadow px-3 py-2 flex flex-col gap-1.5 text-xs"
            style={{
              bottom: sheetOpen
                ? '276px'
                : detailNode !== null
                  ? '196px'
                  : showTabStrip
                    ? '64px'   // 48px strip height + 16px gap
                    : '16px'
            }}
          >
            {routeResult.standard.found && (
              <div className="flex items-center gap-2">
                <span className="w-6 h-1.5 rounded-full bg-blue-500 inline-block" />
                <span className="text-slate-700">Standard</span>
              </div>
            )}
            {routeResult.accessible.found && !routesIdentical && (
              <div className="flex items-center gap-2">
                <span className="w-6 h-1.5 rounded-full bg-green-500 inline-block" />
                <span className="text-slate-700">Accessible</span>
              </div>
            )}
            {routesIdentical && (
              <div className="flex items-center gap-2">
                <span className="w-6 h-1.5 rounded-full bg-blue-500 inline-block" />
                <span className="text-slate-700">Standard (accessible)</span>
              </div>
            )}
          </div>
        )}

      {/* Toast notification */}
      {toast && (
        <div
          className={`fixed bottom-6 left-1/2 -translate-x-1/2 z-40 px-4 py-2 rounded-lg shadow-lg text-sm font-medium transition-opacity ${
            toast.isError ? 'bg-red-500 text-white' : 'bg-slate-800 text-white'
          }`}
        >
          {toast.message}
        </div>
      )}

      {/* Floor tab strip — hidden when DirectionsSheet is open or only 1 floor total */}
      {showTabStrip && (
        <FloorTabStrip
          buildings={nonCampusBuildings}
          campusBuilding={campusBuilding}
          activeBuildingId={activeBuildingId}
          activeFloorId={activeFloorId}
          sortedFloors={sortedActiveFloors}
          onBuildingSwitch={handleBuildingSwitch}
          onFloorSwitch={handleFloorSwitch}
        />
      )}
    </div>
  )
}

/**
 * Core navigation graph type definitions for CampusNav.
 *
 * Two categories of types:
 *
 * 1. **ngraph.graph data types** — `NavNodeData` and `NavEdgeData` are the `.data`
 *    fields stored on ngraph.graph's Node and Link objects via
 *    `graph.addNode(id, data)` and `graph.addLink(from, to, data)`.
 *
 * 2. **Serialization types** — `NavNode`, `NavEdge`, `NavFloor`, `NavBuilding`,
 *    and `NavGraph` are the JSON shapes used for API transport (GET /api/map) and
 *    file storage. The client loads a `NavGraph`, iterates `buildings[].floors[]`,
 *    destructures each node/edge into `(id, data)`, and feeds them into ngraph.graph.
 *    `NavNode` objects live inside `NavFloor.nodes[]`.
 *
 * All coordinates are **NORMALIZED** (0.0–1.0), representing percentages of the
 * floor plan image dimensions. Convert to pixels only at render time:
 * `pixelX = node.x * canvasWidth`.
 */

// ============================================================
// Node Types
// ============================================================

/**
 * Classification of navigation nodes on a floor plan.
 *
 * **Visible to students** (searchable destinations):
 * - `room` — Classroom, office, lab
 * - `entrance` — Building entrance/exit
 * - `elevator` — Elevator (also an accessibility waypoint)
 * - `restroom` — Restroom
 * - `landmark` — Named point of interest (cafeteria, library)
 *
 * **Invisible to students** (routing infrastructure only):
 * - `stairs` — Stairwell navigation waypoint, HIDDEN from student map (routing infrastructure only)
 * - `ramp` — Ramp navigation waypoint, HIDDEN from student map (routing infrastructure only)
 * - `junction` — Hallway intersection
 * - `hallway` — Mid-hallway point
 */
export type NavNodeType =
  | 'room'
  | 'entrance'
  | 'elevator'
  | 'stairs'
  | 'ramp'
  | 'restroom'
  | 'junction'
  | 'hallway'
  | 'landmark'

/**
 * Data stored on each graph node (the `.data` field of an ngraph.graph Node).
 *
 * Coordinates are normalized 0.0–1.0: percentage of floor plan width/height.
 */
export interface NavNodeData {
  /** Normalized x position (0.0 = left edge, 1.0 = right edge of floor plan) */
  x: number
  /** Normalized y position (0.0 = top edge, 1.0 = bottom edge of floor plan) */
  y: number
  /** Display label for search results and turn-by-turn directions */
  label: string
  /** Node classification — determines visibility and search behavior */
  type: NavNodeType
  /** Whether this node appears in student search results */
  searchable: boolean
  /** ID of the floors record this node belongs to (FK → floors.id) */
  floorId: number
  // buildingName REMOVED — derived transitively via floor → building
  /** Room/office number identifier (e.g. "204", "A-102") */
  roomNumber?: string
  /** Human-readable description shown in location detail sheet */
  description?: string
  /** Accessibility information shown in detail sheet */
  accessibilityNotes?: string
  // Floor connector linkage — only set on stairs, elevator, ramp nodes
  /** ID of the floor above that this connector node links to */
  connectsToFloorAboveId?: number
  /** ID of the floor below that this connector node links to */
  connectsToFloorBelowId?: number
  /** ID of the corresponding node on the floor above */
  connectsToNodeAboveId?: string
  /** ID of the corresponding node on the floor below */
  connectsToNodeBelowId?: string
  /** ID of the building this campus entrance marker bridges to (campus map only, entrance nodes) */
  connectsToBuildingId?: number
}

// ============================================================
// Edge Types
// ============================================================

/**
 * Data stored on each graph edge (the `.data` field of an ngraph.graph Link).
 *
 * Every edge carries **dual weights** to enable accessibility routing:
 * - `standardWeight`: cost for the standard walking route
 * - `accessibleWeight`: cost for the wheelchair-accessible route
 *   (same as standard for flat paths; higher for detours like ramps;
 *   `Infinity` for non-accessible edges like stairs)
 */
export interface NavEdgeData {
  /**
   * Walking cost for the standard route.
   * Typically the Euclidean distance between connected nodes in normalized
   * coordinates. Can be overridden by an admin for non-straight paths.
   */
  standardWeight: number
  /**
   * Walking cost for the wheelchair-accessible route.
   * - Same as `standardWeight` for accessible paths.
   * - Higher than `standardWeight` if the accessible path is longer (e.g. ramp).
   * - `Infinity` for non-accessible edges (e.g. stairs without elevator).
   */
  accessibleWeight: number
  /** Whether this edge is traversable by wheelchair */
  accessible: boolean
  /** Whether this edge can be traversed in both directions */
  bidirectional: boolean
  /** Optional admin notes ("3 steps", "narrow doorway", "automatic door") */
  accessibilityNotes?: string
}

// ============================================================
// Serialization Types (API / JSON transport)
// ============================================================

/**
 * A serialized node for JSON transport (API responses, file storage).
 * Combines the node's unique ID with its data fields.
 * NavNode inherits `floorId` from NavNodeData — no direct change needed.
 */
export interface NavNode extends NavNodeData {
  /** Unique identifier for this node (e.g. "room-204", "entrance-main") */
  id: string
}

/**
 * A serialized edge for JSON transport (API responses, file storage).
 * Combines the edge's ID, endpoint references, and data fields.
 */
export interface NavEdge extends NavEdgeData {
  /** Unique identifier for this edge */
  id: string
  /** Source node ID */
  sourceId: string
  /** Target node ID */
  targetId: string
}

/**
 * Optional real-world GPS bounds used to project normalized floor coordinates
 * onto latitude/longitude space.
 */
export interface NavFloorGpsBounds {
  /** Minimum latitude represented by this floor map */
  minLat: number
  /** Maximum latitude represented by this floor map */
  maxLat: number
  /** Minimum longitude represented by this floor map */
  minLng: number
  /** Maximum longitude represented by this floor map */
  maxLng: number
}

/**
 * A single floor within a building, containing all nodes and edges on that floor.
 */
export interface NavFloor {
  /** Database ID of this floor record (floors.id) */
  id: number
  /** Floor number (1-based) */
  floorNumber: number
  /** Path to the floor plan image asset */
  imagePath: string
  /** ISO 8601 timestamp of last graph modification */
  updatedAt: string
  /** Optional GPS calibration bounds for this floor */
  gpsBounds?: NavFloorGpsBounds
  /** All navigation nodes on this floor */
  nodes: NavNode[]
  /** All navigation edges on this floor */
  edges: NavEdge[]
}

/**
 * A building containing one or more floors.
 */
export interface NavBuilding {
  /** Database ID of this building record (buildings.id) */
  id: number
  /** Display name of the building */
  name: string
  /** All floors within this building */
  floors: NavFloor[]
}

/**
 * Complete navigation graph as JSON — returned by `GET /api/map`.
 *
 * The client loads this on page init and builds an ngraph.graph instance
 * by iterating the nested buildings → floors → nodes/edges structure:
 * ```ts
 * const graph = createGraph<NavNodeData, NavEdgeData>()
 * for (const building of navGraph.buildings) {
 *   for (const floor of building.floors) {
 *     for (const { id, ...data } of floor.nodes) graph.addNode(id, data)
 *     for (const { id, sourceId, targetId, ...data } of floor.edges)
 *       graph.addLink(sourceId, targetId, data)
 *   }
 * }
 * ```
 */
export interface NavGraph {
  /** All buildings in the campus, each containing floors with nodes and edges */
  buildings: NavBuilding[]
  // nodes and edges now live under buildings[].floors[].nodes/edges
  // metadata replaced by floors[].updatedAt
}

import type { NavFloorGpsBounds } from '@shared/types'
import { eq } from 'drizzle-orm'
import { db } from './db/client'
import { floors } from './db/schema'

export interface FloorGpsBoundsColumns {
  gpsMinLat: number | null
  gpsMaxLat: number | null
  gpsMinLng: number | null
  gpsMaxLng: number | null
}

export type FloorGpsBoundsErrorCode =
  | 'INVALID_REQUEST'
  | 'GPS_BOUNDS_INCOMPLETE'
  | 'BOUNDS_RANGE_INVALID'
  | 'FLOOR_NOT_FOUND'

type FloorGpsBoundsErrorStatus = 400 | 404

const FLOOR_GPS_BOUNDS_ERROR_STATUS = {
  INVALID_REQUEST: 400,
  GPS_BOUNDS_INCOMPLETE: 400,
  BOUNDS_RANGE_INVALID: 400,
  FLOOR_NOT_FOUND: 404,
} as const satisfies Record<FloorGpsBoundsErrorCode, FloorGpsBoundsErrorStatus>

export class FloorGpsBoundsError extends Error {
  readonly code: FloorGpsBoundsErrorCode
  readonly status: FloorGpsBoundsErrorStatus

  constructor(code: FloorGpsBoundsErrorCode, message: string) {
    super(message)
    this.name = 'FloorGpsBoundsError'
    this.code = code
    this.status = FLOOR_GPS_BOUNDS_ERROR_STATUS[code]
  }
}

export interface FloorGpsBoundsUpdateResult {
  ok: true
  floorId: number
  gpsBounds: NavFloorGpsBounds | null
}

interface FloorGpsBoundsRow extends FloorGpsBoundsColumns {
  id: number
}

export interface FloorGpsBoundsStoreTx {
  getFloorById(floorId: number): Promise<FloorGpsBoundsRow | null>
  updateFloorGpsBounds(floorId: number, bounds: FloorGpsBoundsColumns): Promise<FloorGpsBoundsRow | null>
}

export interface FloorGpsBoundsStore {
  transaction<T>(callback: (tx: FloorGpsBoundsStoreTx) => Promise<T>): Promise<T>
}

type DrizzleFloorGpsBoundsTx = Pick<typeof db, 'select' | 'update'>

function isFiniteNumber(value: unknown): value is number {
  return typeof value === 'number' && Number.isFinite(value)
}

function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === 'object' && value !== null
}

function parseFloorGpsBoundsTuple(values: {
  minLat: unknown
  maxLat: unknown
  minLng: unknown
  maxLng: unknown
}): FloorGpsBoundsColumns {
  const { minLat, maxLat, minLng, maxLng } = values
  const tupleValues = [minLat, maxLat, minLng, maxLng] as const

  if (tupleValues.some(value => value === undefined)) {
    throw new FloorGpsBoundsError(
      'GPS_BOUNDS_INCOMPLETE',
      'minLat, maxLat, minLng, and maxLng must all be provided',
    )
  }

  if (tupleValues.every(value => value === null)) {
    return {
      gpsMinLat: null,
      gpsMaxLat: null,
      gpsMinLng: null,
      gpsMaxLng: null,
    }
  }

  if (tupleValues.some(value => value === null)) {
    throw new FloorGpsBoundsError(
      'GPS_BOUNDS_INCOMPLETE',
      'GPS bounds must be a complete numeric tuple or a full null clear tuple',
    )
  }

  if (
    !isFiniteNumber(minLat)
    || !isFiniteNumber(maxLat)
    || !isFiniteNumber(minLng)
    || !isFiniteNumber(maxLng)
  ) {
    throw new FloorGpsBoundsError(
      'INVALID_REQUEST',
      'minLat, maxLat, minLng, and maxLng must be finite numbers or all null',
    )
  }

  if (minLat >= maxLat || minLng >= maxLng) {
    throw new FloorGpsBoundsError(
      'BOUNDS_RANGE_INVALID',
      'GPS bounds must satisfy minLat < maxLat and minLng < maxLng',
    )
  }

  return {
    gpsMinLat: minLat,
    gpsMaxLat: maxLat,
    gpsMinLng: minLng,
    gpsMaxLng: maxLng,
  }
}

/**
 * Converts nullable DB floor GPS columns into a complete GPS bounds object.
 * Returns null when any value is missing (or non-finite), ensuring callers never
 * serialize partial coordinate tuples.
 */
export function toNavFloorGpsBounds(row: FloorGpsBoundsColumns): NavFloorGpsBounds | null {
  if (
    !isFiniteNumber(row.gpsMinLat)
    || !isFiniteNumber(row.gpsMaxLat)
    || !isFiniteNumber(row.gpsMinLng)
    || !isFiniteNumber(row.gpsMaxLng)
  ) {
    return null
  }

  return {
    minLat: row.gpsMinLat,
    maxLat: row.gpsMaxLat,
    minLng: row.gpsMinLng,
    maxLng: row.gpsMaxLng,
  }
}

export function serializeFloorGpsBounds(row: FloorGpsBoundsColumns): { gpsBounds?: NavFloorGpsBounds } {
  const gpsBounds = toNavFloorGpsBounds(row)
  return gpsBounds ? { gpsBounds } : {}
}

export function parseFloorGpsBoundsUpdatePayload(payload: unknown): FloorGpsBoundsColumns {
  if (!isRecord(payload)) {
    throw new FloorGpsBoundsError('INVALID_REQUEST', 'Request body must be a JSON object')
  }

  return parseFloorGpsBoundsTuple({
    minLat: payload.minLat,
    maxLat: payload.maxLat,
    minLng: payload.minLng,
    maxLng: payload.maxLng,
  })
}

function createDrizzleStoreTx(tx: DrizzleFloorGpsBoundsTx): FloorGpsBoundsStoreTx {
  return {
    async getFloorById(floorId) {
      const [row] = await tx
        .select({
          id: floors.id,
          gpsMinLat: floors.gpsMinLat,
          gpsMaxLat: floors.gpsMaxLat,
          gpsMinLng: floors.gpsMinLng,
          gpsMaxLng: floors.gpsMaxLng,
        })
        .from(floors)
        .where(eq(floors.id, floorId))
        .limit(1)

      return row ?? null
    },

    async updateFloorGpsBounds(floorId, bounds) {
      const [row] = await tx
        .update(floors)
        .set({
          ...bounds,
          updatedAt: new Date().toISOString(),
        })
        .where(eq(floors.id, floorId))
        .returning({
          id: floors.id,
          gpsMinLat: floors.gpsMinLat,
          gpsMaxLat: floors.gpsMaxLat,
          gpsMinLng: floors.gpsMinLng,
          gpsMaxLng: floors.gpsMaxLng,
        })

      return row ?? null
    },
  }
}

const drizzleFloorGpsBoundsStore: FloorGpsBoundsStore = {
  transaction(callback) {
    return db.transaction(async (tx) => callback(createDrizzleStoreTx(tx)))
  },
}

async function executeUpdateFloorGpsBounds(
  tx: FloorGpsBoundsStoreTx,
  floorId: number,
  bounds: FloorGpsBoundsColumns,
): Promise<FloorGpsBoundsUpdateResult> {
  const existingFloor = await tx.getFloorById(floorId)
  if (!existingFloor) {
    throw new FloorGpsBoundsError('FLOOR_NOT_FOUND', `Floor ${floorId} was not found`)
  }

  const updatedFloor = await tx.updateFloorGpsBounds(existingFloor.id, bounds)
  if (!updatedFloor) {
    throw new FloorGpsBoundsError('FLOOR_NOT_FOUND', `Floor ${floorId} was not found`)
  }

  return {
    ok: true,
    floorId: updatedFloor.id,
    gpsBounds: toNavFloorGpsBounds(updatedFloor),
  }
}

export async function updateFloorGpsBounds(
  floorId: number,
  bounds: FloorGpsBoundsColumns,
  options?: { store?: FloorGpsBoundsStore },
): Promise<FloorGpsBoundsUpdateResult> {
  if (!Number.isInteger(floorId) || floorId <= 0) {
    throw new FloorGpsBoundsError('INVALID_REQUEST', 'floorId must be a positive integer')
  }

  const store = options?.store ?? drizzleFloorGpsBoundsStore
  return store.transaction(async (tx) => executeUpdateFloorGpsBounds(tx, floorId, bounds))
}

export async function updateFloorGpsBoundsFromPayload(
  floorId: number,
  payload: unknown,
  options?: { store?: FloorGpsBoundsStore },
): Promise<FloorGpsBoundsUpdateResult> {
  const bounds = parseFloorGpsBoundsUpdatePayload(payload)
  return updateFloorGpsBounds(floorId, bounds, options)
}

import type { NavGraph } from '@shared/types'
import { useEffect, useState } from 'react'

type GraphState =
  | { status: 'loading' }
  | { status: 'loaded'; data: NavGraph }
  | { status: 'error'; message: string }

const MAX_ATTEMPTS = 3
const RETRY_DELAY_MS = 1000

async function fetchWithRetry(signal: AbortSignal): Promise<NavGraph> {
  let lastError: unknown
  for (let attempt = 1; attempt <= MAX_ATTEMPTS; attempt++) {
    try {
      const response = await fetch('/api/map', { signal })
      if (!response.ok) throw new Error(`HTTP ${response.status}`)
      return (await response.json()) as NavGraph
    } catch (err) {
      if (signal.aborted) throw err // Don't retry on cancellation
      lastError = err
      if (attempt < MAX_ATTEMPTS) {
        // Wait before retrying — simple fixed delay
        await new Promise<void>((resolve) => setTimeout(resolve, RETRY_DELAY_MS))
      }
    }
  }
  throw lastError
}

export function useGraphData(): GraphState {
  const [state, setState] = useState<GraphState>({ status: 'loading' })

  useEffect(() => {
    const controller = new AbortController()

    fetchWithRetry(controller.signal)
      .then((data) => {
        if (!controller.signal.aborted) setState({ status: 'loaded', data })
      })
      .catch((err: unknown) => {
        if (!controller.signal.aborted)
          setState({ status: 'error', message: String(err) })
      })

    return () => {
      controller.abort()
    }
  }, [])

  return state
}

import type { NavNode } from '@shared/types'
import { useCallback, useMemo, useState } from 'react'

/* ──────────────── Types ──────────────── */

export interface RouteSelection {
  start: NavNode | null
  destination: NavNode | null
  activeField: 'start' | 'destination'
  bothSelected: boolean
  setStart: (node: NavNode | null) => void
  setDestination: (node: NavNode | null) => void
  setActiveField: (field: 'start' | 'destination') => void
  setFromTap: (node: NavNode) => void
  swap: () => void
  clearStart: () => void
  clearDestination: () => void
  clearAll: () => void
}

/* ──────────────── Hook ──────────────── */

/**
 * Manages route selection state — start (A) and destination (B) nodes.
 *
 * `setFromTap` assigns a tapped node to whichever field `activeField` points to,
 * auto-advancing to the other field afterward. If the tapped node is already the
 * OTHER field, it swaps them instead of duplicating.
 */
export function useRouteSelection(): RouteSelection {
  const [start, setStartState] = useState<NavNode | null>(null)
  const [destination, setDestinationState] = useState<NavNode | null>(null)
  const [activeField, setActiveField] = useState<'start' | 'destination'>('start')

  const setStart = useCallback((node: NavNode | null) => {
    setStartState(node)
    setActiveField('destination')
  }, [])

  const setDestination = useCallback((node: NavNode | null) => {
    setDestinationState(node)
    setActiveField('start')
  }, [])

  const setFromTap = useCallback(
    (node: NavNode) => {
      if (activeField === 'start') {
        // If tapped node is already the destination, swap
        if (destination?.id === node.id) {
          setDestinationState(start)
          setStartState(node)
          setActiveField('destination')
        } else {
          setStartState(node)
          setActiveField('destination')
        }
      } else {
        // activeField === 'destination'
        // If tapped node is already the start, swap
        if (start?.id === node.id) {
          setStartState(destination)
          setDestinationState(node)
          setActiveField('start')
        } else {
          setDestinationState(node)
          setActiveField('start')
        }
      }
    },
    [activeField, start, destination],
  )

  const swap = useCallback(() => {
    if (start === null && destination === null) return
    const prevStart = start
    const prevDest = destination
    setStartState(prevDest)
    setDestinationState(prevStart)
  }, [start, destination])

  const clearStart = useCallback(() => {
    setStartState(null)
    setActiveField('start')
  }, [])

  const clearDestination = useCallback(() => {
    setDestinationState(null)
    setActiveField('destination')
  }, [])

  const clearAll = useCallback(() => {
    setStartState(null)
    setDestinationState(null)
    setActiveField('start')
  }, [])

  const bothSelected = useMemo(() => start !== null && destination !== null, [start, destination])

  return {
    start,
    destination,
    activeField,
    bothSelected,
    setStart,
    setDestination,
    setActiveField,
    setFromTap,
    swap,
    clearStart,
    clearDestination,
    clearAll,
  }
}

import type { NavNode, NavNodeType } from '@shared/types'
import { useCallback, useEffect, useRef, useState } from 'react'
import { useLocationSearch } from '../hooks/useLocationSearch'
import type { RouteSelection } from '../hooks/useRouteSelection'

/* ──────────────── Constants ──────────────── */

const TYPE_COLORS: Record<string, string> = {
  room: '#3b82f6',
  entrance: '#22c55e',
  elevator: '#a855f7',
  restroom: '#f59e0b',
  landmark: '#ef4444',
}

const TYPE_LABELS: Record<string, string> = {
  room: 'Room',
  entrance: 'Entrance',
  elevator: 'Elevator',
  restroom: 'Restroom',
  landmark: 'Landmark',
}

/** POI types available for nearest search */
const NEAREST_POI_TYPES: Array<{ type: NavNodeType; label: string }> = [
  { type: 'restroom', label: 'Nearest Restroom' },
  { type: 'elevator', label: 'Nearest Elevator' },
  { type: 'entrance', label: 'Nearest Entrance' },
]

/* ──────────────── Props ──────────────── */

interface SearchOverlayProps {
  selection: RouteSelection
  nodes: NavNode[]
  onRouteTrigger: () => void
  /** When true (sheet is open), compact strip collapses to a minimal pill */
  sheetOpen?: boolean
  /** Called when user taps the compact A→B strip to reopen the directions sheet */
  onOpenSheet?: () => void
  /** True when a route result is available (sheet can be reopened) */
  hasRoute?: boolean
}

/* ──────────────── Component ──────────────── */

/**
 * Search overlay — dual search bars, full-screen suggestions, compact strip.
 *
 * Rendered as an HTML overlay above the Konva canvas. Uses absolute/fixed
 * positioning with z-index to float above the map.
 */
export function SearchOverlay({
  selection,
  nodes,
  onRouteTrigger,
  sheetOpen = false,
  onOpenSheet,
  hasRoute = false,
}: SearchOverlayProps) {
  const { query, results, search, searchNearest, clearSearch } = useLocationSearch(nodes)
  const [focusedField, setFocusedField] = useState<'start' | 'destination' | null>(null)
  const [showSuggestions, setShowSuggestions] = useState(false)
  const [nearestResults, setNearestResults] = useState<NavNode[]>([])
  const inputRef = useRef<HTMLInputElement>(null)

  // Determine mode: compact when both are selected and not actively searching
  const isCompact = selection.bothSelected && focusedField === null

  // When both become selected, auto-trigger route
  const prevBothRef = useRef(selection.bothSelected)
  useEffect(() => {
    if (selection.bothSelected && !prevBothRef.current) {
      setFocusedField(null)
      setShowSuggestions(false)
      clearSearch()
      onRouteTrigger()
    }
    prevBothRef.current = selection.bothSelected
  }, [selection.bothSelected, onRouteTrigger, clearSearch])

  // Focus input when suggestions panel opens
  useEffect(() => {
    if (showSuggestions && inputRef.current) {
      inputRef.current.focus()
    }
  }, [showSuggestions])

  const handleInputFocus = useCallback(
    (field: 'start' | 'destination') => {
      setFocusedField(field)
      setShowSuggestions(true)
      setNearestResults([])
      selection.setActiveField(field)
      // Reset search when opening a field
      search('')
    },
    [selection, search],
  )

  const handleInputChange = useCallback(
    (value: string) => {
      search(value)
      setNearestResults([])
    },
    [search],
  )

  const handleSelectSuggestion = useCallback(
    (node: NavNode) => {
      if (focusedField === 'start') {
        selection.setStart(node)
      } else if (focusedField === 'destination') {
        selection.setDestination(node)
      }
      setShowSuggestions(false)
      setFocusedField(null)
      clearSearch()
      setNearestResults([])
    },
    [focusedField, selection, clearSearch],
  )

  const handleCloseSuggestions = useCallback(() => {
    setShowSuggestions(false)
    setFocusedField(null)
    clearSearch()
    setNearestResults([])
  }, [clearSearch])

  const handleNearestSearch = useCallback(
    (poiType: NavNodeType) => {
      if (!selection.start) return
      const nearest = searchNearest(selection.start, poiType)
      setNearestResults(nearest)
      // Clear text-based results to show only nearest results
      search('')
    },
    [selection.start, searchNearest, search],
  )

  const handleSwap = useCallback(() => {
    selection.swap()
  }, [selection])

  // Handle keyboard escape
  useEffect(() => {
    const handler = (e: KeyboardEvent) => {
      if (e.key === 'Escape' && showSuggestions) {
        handleCloseSuggestions()
      }
    }
    window.addEventListener('keydown', handler)
    return () => window.removeEventListener('keydown', handler)
  }, [showSuggestions, handleCloseSuggestions])

  // Compact strip mode
  if (isCompact) {
    // When the directions sheet is open, collapse to a minimal pill so it
    // doesn't compete for screen space with the sheet.
    if (sheetOpen) {
      return (
        <div className="absolute top-2 left-2 z-30 pointer-events-auto">
          <div className="bg-white/90 backdrop-blur-sm rounded-xl shadow-lg px-3 py-2 flex items-center gap-2">
            <span className="text-xs text-slate-500 font-medium">Route active</span>
            <button
              type="button"
              className="p-0.5 text-slate-400 hover:text-slate-700"
              onClick={() => selection.clearAll()}
              aria-label="Clear route"
            >
              <ClearIcon />
            </button>
          </div>
        </div>
      )
    }

    return (
      <div className="absolute top-2 left-2 right-2 z-30 pointer-events-auto">
        <div className="bg-white/90 backdrop-blur-sm rounded-xl shadow-lg px-3 py-2 flex items-center gap-2">
          <button
            type="button"
            className="flex-1 min-w-0 flex items-center gap-1 text-sm text-left"
            onClick={() => {
              if (hasRoute && onOpenSheet) {
                onOpenSheet()
              } else {
                setFocusedField(null)
                prevBothRef.current = selection.bothSelected
              }
            }}
          >
            <span className="inline-flex items-center justify-center w-5 h-5 rounded-full bg-green-500 text-white text-xs font-bold shrink-0">
              A
            </span>
            <span className="truncate text-slate-700">{selection.start?.label}</span>
            <span className="text-slate-400 mx-1">&rarr;</span>
            <span className="inline-flex items-center justify-center w-5 h-5 rounded-full bg-red-500 text-white text-xs font-bold shrink-0">
              B
            </span>
            <span className="truncate text-slate-700">{selection.destination?.label}</span>
          </button>
          <button
            type="button"
            className="p-1 text-slate-500 hover:text-slate-700"
            onClick={handleSwap}
            aria-label="Swap start and destination"
          >
            <SwapIcon />
          </button>
          <button
            type="button"
            className="p-1 text-slate-400 hover:text-slate-700"
            onClick={() => selection.clearAll()}
            aria-label="Clear route"
          >
            <ClearIcon />
          </button>
        </div>
      </div>
    )
  }

  // Full-screen suggestions overlay
  if (showSuggestions && focusedField) {
    const displayResults = nearestResults.length > 0 ? nearestResults : results
    const showNearestButtons =
      focusedField === 'destination' && selection.start !== null && query.length < 2

    return (
      <div className="fixed inset-0 z-50 bg-white flex flex-col pointer-events-auto">
        {/* Header with back button and input */}
        <div className="flex items-center gap-2 px-3 py-2 border-b border-slate-200">
          <button
            type="button"
            className="p-2 text-slate-500 hover:text-slate-700"
            onClick={handleCloseSuggestions}
            aria-label="Close search"
          >
            <BackIcon />
          </button>
          <input
            ref={inputRef}
            type="text"
            className="flex-1 py-2 px-3 text-base outline-none bg-transparent placeholder:text-slate-400"
            placeholder={
              focusedField === 'start' ? 'Search start location...' : 'Search destination...'
            }
            value={query}
            onChange={(e) => handleInputChange(e.target.value)}
          />
          {query.length > 0 && (
            <button
              type="button"
              className="p-2 text-slate-400 hover:text-slate-600"
              onClick={() => {
                search('')
                setNearestResults([])
              }}
              aria-label="Clear input"
            >
              <ClearIcon />
            </button>
          )}
        </div>

        {/* Nearest POI quick-filter buttons */}
        {showNearestButtons && (
          <div className="flex gap-2 px-4 py-3 border-b border-slate-100">
            {NEAREST_POI_TYPES.map((poi) => (
              <button
                key={poi.type}
                type="button"
                className="flex-1 py-2 px-3 rounded-lg bg-slate-100 hover:bg-slate-200 text-xs font-medium text-slate-700 transition-colors"
                onClick={() => handleNearestSearch(poi.type)}
              >
                <span
                  className="inline-block w-2 h-2 rounded-full mr-1.5 align-middle"
                  style={{ backgroundColor: TYPE_COLORS[poi.type] }}
                />
                {poi.label}
              </button>
            ))}
          </div>
        )}

        {/* Suggestion list */}
        <div className="flex-1 overflow-y-auto">
          {displayResults.length === 0 && query.length >= 2 && nearestResults.length === 0 && (
            <div className="px-4 py-8 text-center text-slate-400 text-sm">No results found</div>
          )}
          {displayResults.map((node) => (
            <button
              key={node.id}
              type="button"
              className="w-full px-4 py-3 flex items-center gap-3 hover:bg-slate-50 active:bg-slate-100 transition-colors text-left"
              onClick={() => handleSelectSuggestion(node)}
            >
              <span
                className="inline-block w-3 h-3 rounded-full shrink-0"
                style={{ backgroundColor: TYPE_COLORS[node.type] ?? '#64748b' }}
              />
              <div className="flex-1 min-w-0">
                <div className="text-sm font-medium text-slate-800 truncate">{node.label}</div>
                <div className="text-xs text-slate-400 flex gap-1 items-center">
                  {node.roomNumber && (
                    <>
                      <span>Room {node.roomNumber}</span>
                      <span>·</span>
                    </>
                  )}
                  <span>{TYPE_LABELS[node.type] ?? node.type}</span>
                </div>
              </div>
            </button>
          ))}
        </div>
      </div>
    )
  }

  // Expanded mode — dual search bars
  return (
    <div className="absolute top-2 left-2 right-2 z-30 pointer-events-auto">
      <div className="bg-white/90 backdrop-blur-sm rounded-xl shadow-lg p-3">
        <div className="flex items-center gap-2">
          {/* Left: Search fields stacked */}
          <div className="flex-1 flex flex-col gap-2">
            {/* From field */}
            <div className="flex items-center gap-2 bg-slate-50 rounded-lg px-3 py-2">
              <span className="inline-flex items-center justify-center w-5 h-5 rounded-full bg-green-500 text-white text-xs font-bold shrink-0">
                A
              </span>
              <button
                type="button"
                className="flex-1 text-left text-sm truncate"
                onClick={() => handleInputFocus('start')}
              >
                {selection.start ? (
                  <span className="text-slate-800">{selection.start.label}</span>
                ) : (
                  <span className="text-slate-400">Search start location...</span>
                )}
              </button>
              {selection.start && (
                <button
                  type="button"
                  className="p-0.5 text-slate-400 hover:text-slate-600"
                  onClick={() => selection.clearStart()}
                  aria-label="Clear start"
                >
                  <ClearIcon />
                </button>
              )}
            </div>

            {/* To field */}
            <div className="flex items-center gap-2 bg-slate-50 rounded-lg px-3 py-2">
              <span className="inline-flex items-center justify-center w-5 h-5 rounded-full bg-red-500 text-white text-xs font-bold shrink-0">
                B
              </span>
              <button
                type="button"
                className="flex-1 text-left text-sm truncate"
                onClick={() => handleInputFocus('destination')}
              >
                {selection.destination ? (
                  <span className="text-slate-800">{selection.destination.label}</span>
                ) : (
                  <span className="text-slate-400">Search destination...</span>
                )}
              </button>
              {selection.destination && (
                <button
                  type="button"
                  className="p-0.5 text-slate-400 hover:text-slate-600"
                  onClick={() => selection.clearDestination()}
                  aria-label="Clear destination"
                >
                  <ClearIcon />
                </button>
              )}
            </div>
          </div>

          {/* Swap button */}
          <button
            type="button"
            className="p-2 text-slate-500 hover:text-slate-700 self-center"
            onClick={handleSwap}
            aria-label="Swap start and destination"
          >
            <SwapIcon />
          </button>
        </div>
      </div>
    </div>
  )
}

/* ──────────────── Icons ──────────────── */

function SwapIcon() {
  return (
    <svg width="20" height="20" viewBox="0 0 20 20" fill="none" xmlns="http://www.w3.org/2000/svg">
      <title>Swap</title>
      <path
        d="M7 3L7 17M7 17L3 13M7 17L11 13M13 17L13 3M13 3L9 7M13 3L17 7"
        stroke="currentColor"
        strokeWidth="1.5"
        strokeLinecap="round"
        strokeLinejoin="round"
      />
    </svg>
  )
}

function ClearIcon() {
  return (
    <svg width="16" height="16" viewBox="0 0 16 16" fill="none" xmlns="http://www.w3.org/2000/svg">
      <title>Clear</title>
      <path
        d="M4 4L12 12M12 4L4 12"
        stroke="currentColor"
        strokeWidth="1.5"
        strokeLinecap="round"
      />
    </svg>
  )
}

function BackIcon() {
  return (
    <svg width="20" height="20" viewBox="0 0 20 20" fill="none" xmlns="http://www.w3.org/2000/svg">
      <title>Back</title>
      <path
        d="M12 4L6 10L12 16"
        stroke="currentColor"
        strokeWidth="1.5"
        strokeLinecap="round"
        strokeLinejoin="round"
      />
    </svg>
  )
}

import type { NavNode, NavNodeType } from '@shared/types'
import { Layer } from 'react-konva'
import { LandmarkMarker } from './LandmarkMarker'

/* ──────────────── Constants ──────────────── */

const VISIBLE_NODE_TYPES: NavNodeType[] = ['room', 'entrance', 'elevator', 'restroom', 'landmark']

/* ──────────────── Props ──────────────── */

interface LandmarkLayerProps {
  nodes: NavNode[] // received from FloorPlanCanvas
  imageRect: { x: number; y: number; width: number; height: number } | null
  stageScale: number
  selectedNodeId: string | null
  onSelectNode: (node: NavNode) => void
  /** Node IDs to exclude from rendering (e.g. start/dest nodes replaced by A/B pins) */
  hiddenNodeIds?: string[]
  /** Node IDs to render at reduced opacity (e.g. elevator nodes on adjacent floors) */
  dimmedNodeIds?: Set<string>
}

/* ──────────────── Component ──────────────── */

export function LandmarkLayer({
  nodes,
  imageRect,
  stageScale,
  selectedNodeId,
  onSelectNode,
  hiddenNodeIds,
  dimmedNodeIds,
}: LandmarkLayerProps) {
  // Image not yet loaded — no markers
  if (imageRect === null) return null

  const visibleNodes = nodes.filter(
    (n) => VISIBLE_NODE_TYPES.includes(n.type) && !hiddenNodeIds?.includes(n.id),
  )

  return (
    <Layer>
      {visibleNodes.map((node) => (
        <LandmarkMarker
          key={node.id}
          node={node}
          imageRect={imageRect}
          stageScale={stageScale}
          isSelected={node.id === selectedNodeId}
          isLabelVisible={node.id === selectedNodeId || stageScale >= 2.0}
          onClick={() => onSelectNode(node)}
          isDimmed={dimmedNodeIds?.has(node.id) ?? false}
        />
      ))}
    </Layer>
  )
}

import type { NavNode } from '@shared/types'
import { Circle, Group, Text } from 'react-konva'

/* ──────────────── Constants ──────────────── */

const SCREEN_RADIUS = 8

const TYPE_COLORS: Record<string, string> = {
  room: '#3b82f6', // blue
  entrance: '#22c55e', // green
  elevator: '#a855f7', // purple
  restroom: '#f59e0b', // amber
  landmark: '#ef4444', // red
}

/* ──────────────── Props ──────────────── */

interface LandmarkMarkerProps {
  node: NavNode
  imageRect: { x: number; y: number; width: number; height: number }
  stageScale: number
  isSelected: boolean
  isLabelVisible: boolean // true when selected OR stageScale >= 2.0
  onClick: () => void
  isDimmed?: boolean
}

/* ──────────────── Component ──────────────── */

export function LandmarkMarker({
  node,
  imageRect,
  stageScale,
  isSelected,
  isLabelVisible,
  onClick,
  isDimmed,
}: LandmarkMarkerProps) {
  // Convert normalized coordinates to pixel position
  const pixelX = imageRect.x + node.x * imageRect.width
  const pixelY = imageRect.y + node.y * imageRect.height
  const scale = 1 / stageScale
  const fill = TYPE_COLORS[node.type] ?? '#64748b'
  const radius = isSelected ? SCREEN_RADIUS * 1.4 : SCREEN_RADIUS

  return (
    <Group x={pixelX} y={pixelY} scaleX={scale} scaleY={scale} onClick={onClick} onTap={onClick} opacity={isDimmed ? 0.35 : 1}>
      <Circle
        radius={radius}
        fill={fill}
        stroke="#ffffff"
        strokeWidth={2}
        hitFunc={(context, shape) => {
          context.beginPath()
          context.arc(0, 0, SCREEN_RADIUS * 2.5, 0, Math.PI * 2, true)
          context.closePath()
          context.fillStrokeShape(shape)
        }}
      />
      {isLabelVisible && (
        <Text
          text={node.label}
          fontSize={11}
          fill="#1e293b"
          offsetX={0}
          y={radius + 4}
          align="center"
          width={80}
          offsetY={0}
          x={-40}
        />
      )}
    </Group>
  )
}

import type { NavNode } from '@shared/types'
import { Circle, Group, Layer, Text } from 'react-konva'

/* ──────────────── Constants ──────────────── */

const PIN_RADIUS = 12
const LABEL_FONT_SIZE = 14

const START_COLOR = '#22c55e' // green
const DEST_COLOR = '#ef4444' // red

/* ──────────────── Props ──────────────── */

interface SelectionMarkerLayerProps {
  start: NavNode | null
  destination: NavNode | null
  imageRect: { x: number; y: number; width: number; height: number } | null
  stageScale: number
  onClearStart?: () => void
  onClearDestination?: () => void
}

/* ──────────────── Component ──────────────── */

/**
 * Renders A/B labeled pin markers for the selected start and destination nodes.
 *
 * - Start pin: green circle with white "A" label
 * - Destination pin: red circle with white "B" label
 * - Counter-scaled to maintain constant screen size during zoom
 * - Tapping A pin calls onClearStart; tapping B pin calls onClearDestination.
 */
export function SelectionMarkerLayer({
  start,
  destination,
  imageRect,
  stageScale,
  onClearStart,
  onClearDestination,
}: SelectionMarkerLayerProps) {
  if (!imageRect) return null

  const scale = 1 / stageScale

  return (
    <Layer>
      {start && (
        <Group
          x={imageRect.x + start.x * imageRect.width}
          y={imageRect.y + start.y * imageRect.height}
          scaleX={scale}
          scaleY={scale}
          onClick={(e) => { e.cancelBubble = true; onClearStart?.() }}
          onTap={(e) => { e.cancelBubble = true; onClearStart?.() }}
        >
          <Circle
            radius={PIN_RADIUS}
            fill={START_COLOR}
            stroke="#ffffff"
            strokeWidth={2}
            hitFunc={(context, shape) => {
              context.beginPath()
              context.arc(0, 0, PIN_RADIUS * 2.5, 0, Math.PI * 2, true)
              context.closePath()
              context.fillStrokeShape(shape)
            }}
          />
          <Text
            text="A"
            fontSize={LABEL_FONT_SIZE}
            fontStyle="bold"
            fill="#ffffff"
            width={PIN_RADIUS * 2}
            height={PIN_RADIUS * 2}
            offsetX={PIN_RADIUS}
            offsetY={PIN_RADIUS}
            align="center"
            verticalAlign="middle"
          />
        </Group>
      )}
      {destination && (
        <Group
          x={imageRect.x + destination.x * imageRect.width}
          y={imageRect.y + destination.y * imageRect.height}
          scaleX={scale}
          scaleY={scale}
          onClick={(e) => { e.cancelBubble = true; onClearDestination?.() }}
          onTap={(e) => { e.cancelBubble = true; onClearDestination?.() }}
        >
          <Circle
            radius={PIN_RADIUS}
            fill={DEST_COLOR}
            stroke="#ffffff"
            strokeWidth={2}
            hitFunc={(context, shape) => {
              context.beginPath()
              context.arc(0, 0, PIN_RADIUS * 2.5, 0, Math.PI * 2, true)
              context.closePath()
              context.fillStrokeShape(shape)
            }}
          />
          <Text
            text="B"
            fontSize={LABEL_FONT_SIZE}
            fontStyle="bold"
            fill="#ffffff"
            width={PIN_RADIUS * 2}
            height={PIN_RADIUS * 2}
            offsetX={PIN_RADIUS}
            offsetY={PIN_RADIUS}
            align="center"
            verticalAlign="middle"
          />
        </Group>
      )}
    </Layer>
  )
}

import type { NavBuilding, NavNode } from '@shared/types'

/** Elevator is the only connector type visible to students (stairs/ramp are routing-infrastructure only) */
const STUDENT_VISIBLE_CONNECTOR_TYPE = 'elevator' as const

/**
 * Filters nodes for display on the active floor canvas.
 * Returns active-floor nodes at full opacity + adjacent-floor elevator
 * connector nodes shown dimmed so students can locate them.
 *
 * Adjacency rule for dimmed connectors:
 * - Must be type 'elevator' (stairs/ramp remain hidden from students)
 * - Must NOT be on the active floor
 * - Must connect to the active floor (connectsToFloorAboveId or connectsToFloorBelowId === activeFloorId)
 */
export function filterNodesByActiveFloor(
  allNodes: NavNode[],
  activeFloorId: number,
): { nodes: NavNode[]; dimmedNodeIds: Set<string> } {
  const activeFloorNodes = allNodes.filter(n => n.floorId === activeFloorId)
  const dimmedConnectors = allNodes.filter(
    n =>
      n.type === STUDENT_VISIBLE_CONNECTOR_TYPE &&
      n.floorId !== activeFloorId &&
      (n.connectsToFloorAboveId === activeFloorId || n.connectsToFloorBelowId === activeFloorId),
  )
  const nodes = [...activeFloorNodes, ...dimmedConnectors]
  const dimmedNodeIds = new Set(dimmedConnectors.map(n => n.id))
  return { nodes, dimmedNodeIds }
}

/**
 * Filters a route's nodeIds to those belonging to the active floor.
 * Used to render only the active floor's route segment in RouteLayer.
 *
 * Returns [] when no nodeIds map to activeFloorId or nodeMap is empty.
 */
export function filterRouteSegmentByFloor(
  nodeIds: string[],
  nodeMap: Map<string, NavNode>,
  activeFloorId: number,
): string[] {
  return nodeIds.filter(id => nodeMap.get(id)?.floorId === activeFloorId)
}

/**
 * Total number of floors across all buildings.
 * Used to decide whether to show the FloorTabStrip at all.
 * Tab strip is hidden when totalFloorCount <= 1.
 *
 * Returns 0 for empty array, 1 for single-building single-floor campus.
 */
export function totalFloorCount(buildings: NavBuilding[]): number {
  return buildings.reduce((sum, b) => sum + b.floors.length, 0)
}

import type { PathResult } from '@shared/pathfinding/types'
import type { NavFloor, NavNode } from '@shared/types'
import { useMemo } from 'react'

// ============================================================
// Types
// ============================================================

export type StepIcon =
  | 'straight'
  | 'turn-left'
  | 'turn-right'
  | 'sharp-left'
  | 'sharp-right'
  | 'arrive'
  | 'accessible'
  | 'stairs-up'
  | 'stairs-down'
  | 'elevator'
  | 'ramp'

export interface DirectionStep {
  /** Human-readable instruction, e.g. "Turn left at the cafeteria" */
  instruction: string
  icon: StepIcon
  /** Segment distance in normalized units (0–1 coordinate space) */
  distanceM: number
  /** Estimated seconds for this segment */
  durationSec: number
  /** True if this segment passes through a ramp or elevator node */
  isAccessibleSegment: boolean
  /** Floor ID where this instruction is presented */
  floorId: number
  /** Resolved floor number for display/grouping; falls back to floorId when metadata is missing */
  floorNumber: number
}

export interface DirectionsResult {
  steps: DirectionStep[]
  /** Sum of all segment distances in normalized units */
  totalDistanceNorm: number
  /** Sum of all step durations in seconds */
  totalDurationSec: number
}

// ============================================================
// Constants
// ============================================================

const WALKING_SPEED_STANDARD = 0.023 // normalized units/s
const WALKING_SPEED_ACCESSIBLE = 0.013 // normalized units/s

/** Node types that are visible/searchable destinations — eligible for landmark references */
const LANDMARK_TYPES = new Set(['room', 'landmark', 'entrance', 'elevator', 'restroom'])

// ============================================================
// Private helpers
// ============================================================

/**
 * Compute compass bearing in degrees (0–360) from point A to point B.
 * Uses screen-space convention: x increases right, y increases down.
 * atan2(dx, -dy) gives a bearing where 0°=north, 90°=east, 180°=south, 270°=west.
 */
function bearing(ax: number, ay: number, bx: number, by: number): number {
  const dx = bx - ax
  const dy = by - ay
  // atan2(x, -y) → clockwise from north in screen-space
  const rad = Math.atan2(dx, -dy)
  const deg = (rad * 180) / Math.PI
  return (deg + 360) % 360
}

/**
 * Normalize an angle difference to the range [-180, 180].
 */
function normalizeDelta(delta: number): number {
  let d = delta % 360
  if (d > 180) d -= 360
  if (d < -180) d += 360
  return d
}

/**
 * Euclidean distance between two normalized coordinate points.
 */
function euclideanDist(ax: number, ay: number, bx: number, by: number): number {
  const dx = bx - ax
  const dy = by - ay
  return Math.sqrt(dx * dx + dy * dy)
}

/**
 * Resolve a floor number from floor metadata, falling back to floorId when metadata is missing.
 */
function resolveFloorNumber(floorId: number, floorMap: Map<number, NavFloor>): number {
  return floorMap.get(floorId)?.floorNumber ?? floorId
}

/**
 * Determine vertical movement direction between two floors.
 * Uses resolved floor numbers first; if tied, falls back to floorId to keep output deterministic.
 */
function getVerticalDirection(
  fromFloorId: number,
  toFloorId: number,
  floorMap: Map<number, NavFloor>,
): 'up' | 'down' {
  const fromFloorNumber = resolveFloorNumber(fromFloorId, floorMap)
  const toFloorNumber = resolveFloorNumber(toFloorId, floorMap)

  if (toFloorNumber > fromFloorNumber) return 'up'
  if (toFloorNumber < fromFloorNumber) return 'down'

  return toFloorId >= fromFloorId ? 'up' : 'down'
}

/**
 * Classify bearing delta into a step icon.
 */
function classifyTurn(
  delta: number,
): Exclude<StepIcon, 'arrive' | 'accessible' | 'stairs-up' | 'stairs-down' | 'elevator' | 'ramp'> {
  const abs = Math.abs(delta)
  if (abs < 30) return 'straight'
  if (abs < 120) return delta > 0 ? 'turn-right' : 'turn-left'
  return delta > 0 ? 'sharp-right' : 'sharp-left'
}

/**
 * Build the instruction text for a direction step at the current (middle) node.
 * Appends " at the {label}" when the node is a searchable landmark-type.
 */
function buildInstruction(
  icon: Exclude<StepIcon, 'accessible' | 'stairs-up' | 'stairs-down' | 'elevator' | 'ramp'>,
  node: NavNode,
): string {
  const base: Record<
    Exclude<StepIcon, 'accessible' | 'stairs-up' | 'stairs-down' | 'elevator' | 'ramp'>,
    string
  > = {
    straight: 'Continue straight',
    'turn-left': 'Turn left',
    'turn-right': 'Turn right',
    'sharp-left': 'Sharp left',
    'sharp-right': 'Sharp right',
    arrive: `Arrive at ${node.label}`,
  }

  const text = base[icon]

  // For non-arrive steps: append landmark reference if the node is a visible, searchable destination
  if (icon !== 'arrive' && LANDMARK_TYPES.has(node.type) && node.searchable) {
    return `${text} at the ${node.label}`
  }

  return text
}

// ============================================================
// Core function
// ============================================================

/**
 * Convert an ordered list of node IDs into turn-by-turn walking directions.
 *
 * Algorithm:
 * - 0 or 1 nodes → empty result
 * - 2 nodes → single "arrive" step (no turn to compute)
 * - N nodes → for each triple (prev, curr, next): classify bearing delta → build step
 *             then append final "arrive" step for the last node
 */
export function generateDirections(
  nodeIds: string[],
  nodeMap: Map<string, NavNode>,
  mode: 'standard' | 'accessible',
  floorMap: Map<number, NavFloor> = new Map(),
): DirectionsResult {
  if (nodeIds.length < 2) {
    return { steps: [], totalDistanceNorm: 0, totalDurationSec: 0 }
  }

  const speed = mode === 'accessible' ? WALKING_SPEED_ACCESSIBLE : WALKING_SPEED_STANDARD
  const steps: DirectionStep[] = []
  let totalDistanceNorm = 0

  // Process intermediate nodes (all except the first and last)
  for (let i = 1; i < nodeIds.length - 1; i++) {
    // noUncheckedIndexedAccess: bounds are guaranteed by the for-loop condition
    const prevId = nodeIds[i - 1] as string
    const currId = nodeIds[i] as string
    const nextId = nodeIds[i + 1] as string

    // Nodes are guaranteed to be in the map when the caller provides valid IDs
    const prev = nodeMap.get(prevId)
    const curr = nodeMap.get(currId)
    const next = nodeMap.get(nextId)
    if (prev === undefined || curr === undefined || next === undefined) continue

    const distanceM = euclideanDist(prev.x, prev.y, curr.x, curr.y)
    const durationSec = distanceM / speed
    const currFloorNumber = resolveFloorNumber(curr.floorId, floorMap)
    const nextFloorNumber = resolveFloorNumber(next.floorId, floorMap)

    // Floor-change detection: check if curr→next crosses a floor boundary
    if (curr.floorId !== next.floorId) {
      const verticalDirection = getVerticalDirection(curr.floorId, next.floorId, floorMap)

      // Determine direction icon based on connector type and vertical direction
      let icon: StepIcon
      if (curr.type === 'stairs') {
        icon = verticalDirection === 'up' ? 'stairs-up' : 'stairs-down'
      } else if (curr.type === 'elevator') {
        icon = 'elevator'
      } else if (curr.type === 'ramp') {
        icon = 'ramp'
      } else {
        // Fallback: should not occur in a well-formed graph
        icon = verticalDirection === 'up' ? 'stairs-up' : 'stairs-down'
      }

      // Determine connector type name for instruction text
      const connectorTypeName =
        curr.type === 'elevator' ? 'elevator' : curr.type === 'ramp' ? 'ramp' : 'stairs'

      const instruction = `Take the ${connectorTypeName} ${verticalDirection} to Floor ${nextFloorNumber}`
      const isAccessibleSegment = curr.type === 'elevator' || curr.type === 'ramp'

      steps.push({
        instruction,
        icon,
        distanceM,
        durationSec,
        isAccessibleSegment,
        floorId: curr.floorId,
        floorNumber: currFloorNumber,
      })
      totalDistanceNorm += distanceM
      continue
    }

    const inBearing = bearing(prev.x, prev.y, curr.x, curr.y)
    const outBearing = bearing(curr.x, curr.y, next.x, next.y)
    const delta = normalizeDelta(outBearing - inBearing)

    const icon = classifyTurn(delta)
    const instruction = buildInstruction(icon, curr)
    const isAccessibleSegment = curr.type === 'ramp' || curr.type === 'elevator'

    steps.push({
      instruction,
      icon,
      distanceM,
      durationSec,
      isAccessibleSegment,
      floorId: curr.floorId,
      floorNumber: currFloorNumber,
    })
    totalDistanceNorm += distanceM
  }

  // Final "arrive" step — distance from second-to-last to last node
  const lastPrevId = nodeIds[nodeIds.length - 2] as string
  const lastId = nodeIds[nodeIds.length - 1] as string
  const lastPrev = nodeMap.get(lastPrevId)
  const last = nodeMap.get(lastId)
  if (lastPrev === undefined || last === undefined) {
    return { steps: [], totalDistanceNorm: 0, totalDurationSec: 0 }
  }

  const arriveDistance = euclideanDist(lastPrev.x, lastPrev.y, last.x, last.y)
  const arriveDuration = arriveDistance / speed
  const arriveInstruction = buildInstruction('arrive', last)

  steps.push({
    instruction: arriveInstruction,
    icon: 'arrive',
    distanceM: arriveDistance,
    durationSec: arriveDuration,
    isAccessibleSegment: last.type === 'ramp' || last.type === 'elevator',
    floorId: last.floorId,
    floorNumber: resolveFloorNumber(last.floorId, floorMap),
  })

  totalDistanceNorm += arriveDistance
  const totalDurationSec = steps.reduce((sum, s) => sum + s.durationSec, 0)

  return { steps, totalDistanceNorm, totalDurationSec }
}

// ============================================================
// routesAreIdentical utility
// ============================================================

/**
 * Returns true only if both routes were found and share the exact same ordered node IDs.
 */
export function routesAreIdentical(a: PathResult, b: PathResult): boolean {
  if (!a.found || !b.found) return false
  if (a.nodeIds.length !== b.nodeIds.length) return false
  return a.nodeIds.every((id, i) => id === b.nodeIds[i])
}

// ============================================================
// Hook
// ============================================================

/**
 * Memoized hook that converts a PathResult into turn-by-turn walking directions.
 *
 * Returns an empty result when:
 * - pathResult is null
 * - pathResult.found is false
 * - pathResult has fewer than 2 nodeIds
 */
export function useRouteDirections(
  pathResult: PathResult | null,
  nodeMap: Map<string, NavNode>,
  mode: 'standard' | 'accessible',
  floorMap?: Map<number, NavFloor>,
): DirectionsResult {
  return useMemo(() => {
    if (pathResult === null || !pathResult.found) {
      return { steps: [], totalDistanceNorm: 0, totalDurationSec: 0 }
    }
    return generateDirections(pathResult.nodeIds, nodeMap, mode, floorMap)
  }, [pathResult, nodeMap, mode, floorMap])
}

/**
 * PathfindingEngine — dual-mode A* with accessibility filtering.
 *
 * Wraps ngraph.path's A* algorithm with the project's type system.
 * Takes a NavGraph, builds an internal ngraph.graph, and exposes
 * findRoute(fromId, toId, mode) for standard and accessible routing.
 *
 * Used by Phase 6 (route visualization) and Phase 7 (turn-by-turn).
 */

import { buildGraph, calculateWeight } from '@shared/pathfinding/graph-builder'
import type { PathResult, PathSegment, RouteMode } from '@shared/pathfinding/types'
import type { NavEdgeData, NavGraph, NavNodeData } from '@shared/types'
import type { Graph, Link, Node } from 'ngraph.graph'
import type { PathFinder } from 'ngraph.path'
import { aStar } from 'ngraph.path'

/** Not-found result constant — reused for all failure responses. */
const NOT_FOUND: PathResult = Object.freeze({
  found: false,
  nodeIds: [],
  totalDistance: 0,
  segments: [],
})

export class PathfindingEngine {
  private readonly graph: Graph<NavNodeData, NavEdgeData>
  private readonly standardFinder: PathFinder<NavNodeData>
  private readonly accessibleFinder: PathFinder<NavNodeData>

  constructor(navGraph: NavGraph) {
    this.graph = buildGraph(navGraph)

    // Standard finder: uses standardWeight, no edge blocking
    this.standardFinder = aStar<NavNodeData, NavEdgeData>(this.graph, {
      distance: (_from: Node<NavNodeData>, _to: Node<NavNodeData>, link: Link<NavEdgeData>) =>
        link.data.standardWeight,
      heuristic: (a: Node<NavNodeData>, b: Node<NavNodeData>) =>
        a.data.floorId !== b.data.floorId
          ? 0
          : calculateWeight(a.data.x, a.data.y, b.data.x, b.data.y),
    })

    // Accessible finder: uses accessibleWeight, blocks non-accessible edges
    this.accessibleFinder = aStar<NavNodeData, NavEdgeData>(this.graph, {
      distance: (_from: Node<NavNodeData>, _to: Node<NavNodeData>, link: Link<NavEdgeData>) =>
        link.data.accessibleWeight,
      heuristic: (a: Node<NavNodeData>, b: Node<NavNodeData>) =>
        a.data.floorId !== b.data.floorId
          ? 0
          : calculateWeight(a.data.x, a.data.y, b.data.x, b.data.y),
      blocked: (_from: Node<NavNodeData>, _to: Node<NavNodeData>, link: Link<NavEdgeData>) =>
        !link.data.accessible,
    })
  }

  /**
   * Find a route between two nodes.
   *
   * @param fromId - Source node ID
   * @param toId - Destination node ID
   * @param mode - 'standard' or 'accessible'
   * @returns PathResult with found status, ordered nodeIds, segments, and totalDistance
   */
  findRoute(fromId: string, toId: string, mode: RouteMode): PathResult {
    // Same start and destination: trivial path
    if (fromId === toId) {
      return { found: true, nodeIds: [fromId], totalDistance: 0, segments: [] }
    }

    // Validate node existence before calling finder (ngraph throws on missing nodes)
    if (!this.graph.hasNode(fromId) || !this.graph.hasNode(toId)) {
      return { ...NOT_FOUND }
    }

    const finder = mode === 'accessible' ? this.accessibleFinder : this.standardFinder

    const rawPath = finder.find(fromId, toId)

    // ngraph.path returns [targetNode] when all paths are blocked — not a valid path
    if (rawPath.length <= 1) {
      return { ...NOT_FOUND }
    }

    // ngraph.path returns destination-first — reverse to get source-first order
    const path = rawPath.reverse()

    const nodeIds: string[] = []
    const segments: PathSegment[] = []
    let totalDistance = 0

    for (let i = 0; i < path.length; i++) {
      const node = path[i]
      if (!node) continue
      const nodeId = node.id as string
      nodeIds.push(nodeId)

      if (i > 0) {
        const prevNode = path[i - 1]
        if (!prevNode) continue
        const prevId = prevNode.id as string
        const link = this.graph.getLink(prevId, nodeId)

        const distance =
          link != null
            ? mode === 'accessible'
              ? link.data.accessibleWeight
              : link.data.standardWeight
            : 0

        segments.push({ fromId: prevId, toId: nodeId, distance })
        totalDistance += distance
      }
    }

    return { found: true, nodeIds, totalDistance, segments }
  }
}
